content.oldText:
process.env.MEMORY_DIR = "G:\\AI\\AIMemory";
process.env.TELEGRAM_BOT_TOKEN = "dummy";

const { rebuildShards } = await import("../dist/facts-store.js");

try {
  const result = await rebuildShards("509424983");
  const fs = await import("node:fs");
  fs.writeFileSync("G:\\AI\\AIMemory\\tmp_rebuild_result.txt", JSON.stringify(result, null, 2));
  console.log("OK:", JSON.stringify(result));
} catch (e) {
  const fs = await import("node:fs");
  fs.writeFileSync("G:\\AI\\AIMemory\\tmp_rebuild_result.txt", "ERROR: " + e.message + "\n" + e.stack);
  console.error("FAIL:", e.message);
}

